+    preimage.push(0xff);
+    preimage.extend_from_slice(&checkpoint_stub.log_length.to_be_bytes());
+    preimage.push(0xff);
+    preimage.extend_from_slice(checkpoint_stub.root_hash.as_bytes());
+    preimage.push(0xff);
